// generated by sprint 61-1 — macOS build pipeline orchestration

import {
  type MacOSBuildConfig,
  type BuildResult,
  type BuildEnvironment,
} from "./types";
import { createDefaultBuildConfig } from "./tauri-config";
import { generateDmgBuildStages, type DmgBuildStage } from "./dmg-builder";
import { resolveSigningIdentityFromEnv } from "./codesign";
import { resolveNotarizationConfigFromEnv } from "./notarize";
import { validateBuildConfig, validateBuildEnvironment } from "./validate";

export interface PipelineOptions {
  readonly version: string;
  readonly skipSigning: boolean;
  readonly skipNotarization: boolean;
  readonly dryRun: boolean;
  readonly verbose: boolean;
}

export interface PipelineStageResult {
  readonly stage: string;
  readonly status: "success" | "skipped" | "failed";
  readonly durationMs: number;
  readonly output: string;
  readonly error: string | null;
}

export interface PipelineExecution {
  readonly config: MacOSBuildConfig;
  readonly stages: DmgBuildStage[];
  readonly stageResults: PipelineStageResult[];
  readonly result: BuildResult;
}

export function preparePipeline(
  options: PipelineOptions
): {
  config: MacOSBuildConfig;
  stages: DmgBuildStage[];
  validationErrors: string[];
} {
  const signingIdentity = options.skipSigning
    ? null
    : resolveSigningIdentityFromEnv();

  const notarization =
    options.skipNotarization || options.skipSigning
      ? null
      : resolveNotarizationConfigFromEnv();

  const config: MacOSBuildConfig = {
    ...createDefaultBuildConfig(
      options.version,
      signingIdentity?.identity,
      signingIdentity?.teamId
    ),
    signingIdentity,
    notarization,
  };

  const configValidation = validateBuildConfig(config);
  const validationErrors = configValidation.checks
    .filter((c) => !c.passed && c.severity === "error")
    .map((c) => `[${c.name}] ${c.message}`);

  const stages = generateDmgBuildStages(config);

  return { config, stages, validationErrors };
}

export function formatStageCommands(stage: DmgBuildStage): string {
  return stage.commands
    .map((cmd) => cmd.join(" "))
    .join("\n");
}

export function printPipelinePlan(
  stages: DmgBuildStage[],
  verbose: boolean
): string {
  const lines: string[] = [
    "=== macOS .dmg Build Pipeline ===",
    "",
  ];

  for (let i = 0; i < stages.length; i++) {
    const stage = stages[i];
    const marker = stage.required ? "[REQUIRED]" : "[OPTIONAL]";
    lines.push(`${i + 1}. ${stage.name} ${marker}`);
    lines.push(`   ${stage.description}`);

    if (verbose) {
      for (const cmd of stage.commands) {
        lines.push(`   $ ${cmd.join(" ")}`);
      }
    }

    lines.push("");
  }

  return lines.join("\n");
}

export function detectBuildEnvironment(): BuildEnvironment {
  const arch = process.arch === "arm64" ? "aarch64" : "x86_64";

  return {
    arch: arch as "x86_64" | "aarch64",
    osVersion: process.env.MACOS_VERSION ?? "unknown",
    xcodeVersion: process.env.XCODE_VERSION ?? null,
    rustVersion: process.env.RUSTC_VERSION ?? "unknown",
    nodeVersion: process.version,
    tauriCliVersion: process.env.TAURI_CLI_VERSION ?? "unknown",
  };
}

export function generateBuildScript(
  options: PipelineOptions
): string {
  const { config, stages, validationErrors } = preparePipeline(options);

  if (validationErrors.length > 0) {
    return [
      "#!/bin/bash",
      "set -euo pipefail",
      "",
      "echo 'Build configuration validation failed:'",
      ...validationErrors.map((e) => `echo '  - ${e}'`),
      "exit 1",
    ].join("\n");
  }

  const lines: string[] = [
    "#!/bin/bash",
    "set -euo pipefail",
    "",
    `# macOS .dmg build script for ${config.appName} v${config.version}`,
    `# Generated for sprint 61-1`,
    `# Targets: macOS universal binary (x86_64 + aarch64)`,
    "",
    `VERSION="${config.version}"`,
    `APP_NAME="${config.appName}"`,
    `BUNDLE_ID="${config.bundleIdentifier}"`,
    "",
  ];

  for (const stage of stages) {
    lines.push(`echo "=== Stage: ${stage.name} ==="`);
    lines.push(`echo "${stage.description}"`);

    if (options.dryRun) {
      for (const cmd of stage.commands) {
        lines.push(`echo "[DRY RUN] ${cmd.join(" ")}"`);
      }
    } else {
      for (const cmd of stage.commands) {
        lines.push(cmd.join(" "));
      }
    }

    lines.push(`echo "=== ${stage.name} complete ==="`, "");
  }

  lines.push('echo "macOS .dmg build complete"');

  return lines.join("\n");
}

export function resolveArtifactUploadPaths(
  config: MacOSBuildConfig
): string[] {
  const sanitized = config.appName.toLowerCase().replace(/\s+/g, "-");
  const baseName = `${sanitized}-${config.version}-macos-universal`;

  return [
    `dist/${baseName}.dmg`,
    `dist/${baseName}.dmg.sha256`,
  ];
}
